import re
text = open('_response.md').read()
blocks = re.findall(r'```mermaid\n(.*?)```', text, re.S)
print("mermaid blocks:", len(blocks))
bad_chars = set('():;/"<>{}')
# allow square brackets as node-shape delimiters, but flag them inside label text
for bi,b in enumerate(blocks,1):
    issues=[]
    for ln in b.splitlines():
        # extract text inside node labels [ ... ] [( ... )] [[ ... ]] and edge labels |"..."| or |...|
        # node labels
        for m in re.findall(r'\[\(?\[?(.*?)\]?\)?\]', ln):
            for ch in m:
                if ch in bad_chars:
                    issues.append((ln.strip(), 'label', m, ch))
                    break
        # edge labels
        for m in re.findall(r'\|"?(.*?)"?\|', ln):
            for ch in m:
                if ch in bad_chars:
                    issues.append((ln.strip(), 'edge', m, ch))
                    break
    if issues:
        print(f"--- block {bi}: {len(issues)} issue(s)")
        for it in issues:
            print("   ", it)
    else:
        print(f"--- block {bi}: clean")
